mapper.select:
SELECT dp.*, d.number as device_number
FROM device_photos dp
JOIN devices d ON dp.device_id = d.id
WHERE dp.customer_id = #{customerId}

    AND dp.device_id = #{deviceId}


    AND (
        dp.file_name ILIKE #{search}
        OR dp.description ILIKE #{search}
        OR dp.tags ILIKE #{search}
        OR d.number ILIKE #{search}
    )

ORDER BY dp.created_at DESC

mapper.update:
UPDATE device_photos
SET description = #{description},
    tags = #{tags}
WHERE id = #{id}

UPDATE photo_upload_requests
SET status = #{status},
    photo_count = COALESCE(#{photoCount}, photo_count),
    completed_at = CASE WHEN #{status} IN ('COMPLETED', 'FAILED', 'CANCELLED') THEN CURRENT_TIMESTAMP ELSE completed_at END,
    error_message = #{errorMessage}
WHERE id = #{id}
